authMiddleware.js
const jwt = require('jsonwebtoken');

// Configuration for JWT verification
// IMPORTANT: In a production environment, use strong, unique keys.
// For symmetric keys: process.env.JWT_SECRET (e.g., a base64 encoded string)
// For asymmetric keys (e.g., RS256, ES256, PS256): process.env.JWT_PUBLIC_KEY
//      - The public key should be the public part of the Authorization Server's signing key,
//        often fetched from a JWKS endpoint (e.g., '-----BEGIN PUBLIC KEY-----\nMIIBIj...\n-----END PUBLIC KEY-----')
const JWT_SECRET = process.env.JWT_SECRET || 'your_super_secret_key_change_me_in_production';
const JWT_PUBLIC_KEY = process.env.JWT_PUBLIC_KEY; // For asymmetric algorithms

// Optional: Validate issuer and audience for increased security
// JWT_ISSUER: The entity that issued the JWT (e.g., 'https://your-auth-server.com/')
// JWT_AUDIENCE: The intended recipient of the JWT (e.g., 'your-api-gateway-service')
const JWT_ISSUER = process.env.JWT_ISSUER;
const JWT_AUDIENCE = process.env.JWT_AUDIENCE;

function authenticateToken(req, res, next) {
    const authHeader = req.headers['authorization'];
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
        console.error('Authorization header missing or not in Bearer format.');
        return res.status(401).json({ message: 'Unauthorized: No token provided or invalid format.' });
    }

    const token = authHeader.split(' ')[1];

    if (!token) {
        console.error('Token is null or empty after splitting header.');
        return res.status(401).json({ message: 'Unauthorized: Token value missing.' });
    }

    const verifyOptions = {};
    const signingKey = JWT_PUBLIC_KEY || JWT_SECRET; // Prefer public key if provided, else use secret

    if (!signingKey) {
        console.error('Server configuration error: JWT_SECRET or JWT_PUBLIC_KEY must be set.');
        return res.status(500).json({ message: 'Server configuration error: JWT verification key not found.' });
    }

    // If using asymmetric keys (like RS256), you might also specify the algorithm
    // verifyOptions.algorithms = ['RS256'];

    if (JWT_ISSUER) {
        verifyOptions.issuer = JWT_ISSUER;
    }
    if (JWT_AUDIENCE) {
        verifyOptions.audience = JWT_AUDIENCE;
    }

    jwt.verify(token, signingKey, verifyOptions, (err, decoded) => {
        if (err) {
            console.error('Token verification failed:', err.name, '-', err.message);
            if (err.name === 'TokenExpiredError') {
                return res.status(401).json({ message: 'Unauthorized: Access token expired.' });
            }
            if (err.name === 'JsonWebTokenError') {
                return res.status(403).json({ message: 'Forbidden: Invalid access token.' });
            }
            return res.status(403).json({ message: 'Forbidden: Authentication failed.' });
        }
        // Token is valid. Attach the decoded payload to the request object.
        // This payload typically contains user information (sub, username, roles, etc.)
        req.user = decoded;
        next(); // Proceed to the next middleware or route handler
    });
}

module.exports = authenticateToken;

server.js
const express = require('express');
const authenticateToken = require('./authMiddleware');
const jwt = require('jsonwebtoken'); // Only for test token generation endpoint

const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.json()); // Middleware to parse JSON request bodies

// --- Public Route Example ---
// This endpoint does not require an access token.
app.get('/public', (req, res) => {
    res.json({ message: 'This is a public endpoint. Anyone can access it.' });
});

// --- Test Token Generation (for development/testing purposes ONLY) ---
// In a real OAuth 2.0 flow, an Authorization Server would issue tokens,
// not the Resource Server (API Gateway).
app.get('/generate-test-token', (req, res) => {
    const JWT_SECRET_FOR_TEST = process.env.JWT_SECRET || 'your_super_secret_key_change_me_in_production';
    if (JWT_SECRET_FOR_TEST === 'your_super_secret_key_change_me_in_production') {
        console.warn('WARNING: Using default JWT_SECRET. Set JWT_SECRET environment variable for production.');
    }

    // Example payload for a test user
    const testPayload = {
        sub: 'testuser123', // Subject (user ID)
        username: 'apiuser',
        roles: ['admin', 'user'],
        aud: process.env.JWT_AUDIENCE || undefined, // Audience for the token
        iss: process.env.JWT_ISSUER || 'http://localhost:3000' // Issuer of the token
    };

    const token = jwt.sign(testPayload, JWT_SECRET_FOR_TEST, { expiresIn: '1h' });
    res.json({
        message: 'A test access token has been generated. Use it in the Authorization: Bearer header.',
        token: token
    });
});

// --- Authentication Middleware Application ---
// All routes defined AFTER this line will require a valid access token.
app.use(authenticateToken);

// --- Protected Route Examples ---
// These endpoints require a valid access token.
app.get('/protected', (req, res) => {
    // req.user contains the decoded payload from the access token
    res.json({
        message: `Welcome ${req.user.username || req.user.sub}! This is a protected endpoint.`,
        user_info: req.user
    });
});

app.get('/protected/profile', (req, res) => {
    res.json({
        message: `Displaying profile for user: ${req.user.username || req.user.sub}.`,
        profile_data: {
            id: req.user.sub,
            username: req.user.username,
            roles: req.user.roles,
            issued_at: new Date(req.user.iat * 1000).toISOString(),
            expires_at: new Date(req.user.exp * 1000).toISOString()
        }
    });
});

// Start the server
app.listen(PORT, () => {
    console.log(`OAuth 2.0 Resource Server listening on port ${PORT}`);
    console.log(`Public endpoint: http://localhost:${PORT}/public`);
    console.log(`Generate test token: http://localhost:${PORT}/generate-test-token`);
    console.log(`Protected endpoint: http://localhost:${PORT}/protected (requires Authorization: Bearer <token>)`);
});